// ============================================================
// HydraNet - Teams API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { EntityStatus } from '@prisma/client'

// GET /api/teams - List all teams
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const dmaId = searchParams.get('dmaId')
    const branchId = searchParams.get('branchId')

    const teams = await prisma.team.findMany({
      where: {
        ...(dmaId && { dmaId }),
        ...(branchId && { branchId }),
      },
      include: {
        branch: { 
          select: { id: true, name: true, utilityId: true } 
        },
        dma: { 
          select: { id: true, name: true, utilityId: true } 
        },
        leader: { 
          select: { id: true, name: true, email: true, role: true } 
        },
        engineers: { 
          select: { id: true, name: true, email: true, role: true, status: true } 
        },
        _count: { select: { engineers: true, reports: true } },
      },
      orderBy: { name: 'asc' },
    })

    const formattedTeams = teams.map((team) => ({
      ...team,
      branchName: team.branch.name,
      utilityId: team.branch.utilityId,
      dmaName: team.dma.name,
      leaderName: team.leader?.name,
      memberCount: team._count.engineers,
      activeReports: team._count.reports,
      engineerIds: team.engineers.map(e => e.id),
    }))

    return NextResponse.json(formattedTeams)
  } catch (error) {
    console.error('Error fetching teams:', error)
    return NextResponse.json({ error: 'Failed to fetch teams' }, { status: 500 })
  }
}

// POST /api/teams - Create a new team
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Validate required fields
    if (!data.name?.trim()) {
      return NextResponse.json({ error: 'Team name is required' }, { status: 400 })
    }
    if (!data.branchId) {
      return NextResponse.json({ error: 'Branch is required' }, { status: 400 })
    }
    if (!data.dmaId) {
      return NextResponse.json({ error: 'DMA ID is required' }, { status: 400 })
    }

    // Check if team name already exists in this branch
    const existingTeam = await prisma.team.findFirst({
      where: {
        name: data.name.trim(),
        branchId: data.branchId,
      },
    })

    if (existingTeam) {
      return NextResponse.json(
        { error: 'A team with this name already exists in this branch' },
        { status: 400 }
      )
    }

    // Get the branch to verify it belongs to the DMA
    const branch = await prisma.branch.findUnique({
      where: { id: data.branchId },
      select: { id: true, dmaId: true, utilityId: true },
    })

    if (!branch) {
      return NextResponse.json({ error: 'Branch not found' }, { status: 404 })
    }

    if (branch.dmaId !== data.dmaId) {
      return NextResponse.json(
        { error: 'Branch does not belong to the specified DMA' },
        { status: 400 }
      )
    }

    const team = await prisma.team.create({
      data: {
        name: data.name.trim(),
        description: data.description?.trim() || null,
        branchId: data.branchId,
        dmaId: data.dmaId,
        leaderId: null, // Leader is assigned separately via leader API
        status: (data.status as EntityStatus) || 'active',
      },
      include: {
        branch: { select: { id: true, name: true, utilityId: true } },
        dma: { select: { id: true, name: true } },
        leader: { select: { id: true, name: true, email: true } },
        engineers: { select: { id: true, name: true, email: true } },
      },
    })

    return NextResponse.json({
      ...team,
      branchName: team.branch.name,
      utilityId: team.branch.utilityId,
      dmaName: team.dma.name,
      leaderName: team.leader?.name,
      memberCount: team.engineers.length,
      engineerIds: team.engineers.map(e => e.id),
    }, { status: 201 })
  } catch (error) {
    console.error('Error creating team:', error)
    return NextResponse.json({ error: 'Failed to create team' }, { status: 500 })
  }
}

// PUT /api/teams - Update a team
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    if (!data.id) {
      return NextResponse.json({ error: 'Team ID is required' }, { status: 400 })
    }

    // Validate required fields
    if (!data.name?.trim()) {
      return NextResponse.json({ error: 'Team name is required' }, { status: 400 })
    }
    if (!data.branchId) {
      return NextResponse.json({ error: 'Branch is required' }, { status: 400 })
    }

    // Check if team exists
    const existingTeam = await prisma.team.findUnique({
      where: { id: data.id },
      include: {
        engineers: { select: { id: true, branchId: true } },
        leader: { select: { id: true, branchId: true } },
      },
    })

    if (!existingTeam) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    // Check if team name already exists in this branch (excluding current team)
    const duplicateName = await prisma.team.findFirst({
      where: {
        name: data.name.trim(),
        branchId: data.branchId,
        NOT: { id: data.id },
      },
    })

    if (duplicateName) {
      return NextResponse.json(
        { error: 'A team with this name already exists in this branch' },
        { status: 400 }
      )
    }

    // If branch is changing, we need to handle members and leader
    if (data.branchId !== existingTeam.branchId) {
      // Check if any members exist - they must match the new branch
      if (existingTeam.engineers.length > 0) {
        return NextResponse.json(
          { error: 'Cannot change branch while team has members. Remove all members first.' },
          { status: 400 }
        )
      }

      // Check if leader exists - must match the new branch
      if (existingTeam.leader) {
        return NextResponse.json(
          { error: 'Cannot change branch while team has a leader. Remove the leader first.' },
          { status: 400 }
        )
      }
    }

    const team = await prisma.team.update({
      where: { id: data.id },
      data: {
        name: data.name.trim(),
        description: data.description?.trim() || null,
        branchId: data.branchId,
        status: data.status as EntityStatus,
      },
      include: {
        branch: { select: { id: true, name: true, utilityId: true } },
        dma: { select: { id: true, name: true } },
        leader: { select: { id: true, name: true, email: true, role: true } },
        engineers: { select: { id: true, name: true, email: true, role: true, status: true } },
        _count: { select: { engineers: true, reports: true } },
      },
    })

    return NextResponse.json({
      ...team,
      branchName: team.branch.name,
      utilityId: team.branch.utilityId,
      dmaName: team.dma.name,
      leaderName: team.leader?.name,
      memberCount: team._count.engineers,
      activeReports: team._count.reports,
      engineerIds: team.engineers.map(e => e.id),
    })
  } catch (error) {
    console.error('Error updating team:', error)
    return NextResponse.json({ error: 'Failed to update team' }, { status: 500 })
  }
}

// DELETE /api/teams - Delete a team
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')

    if (!id) {
      return NextResponse.json({ error: 'Team ID is required' }, { status: 400 })
    }

    // Check if team exists
    const team = await prisma.team.findUnique({
      where: { id },
      include: {
        engineers: { select: { id: true } },
        leader: { select: { id: true } },
      },
    })

    if (!team) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    // Use a transaction to ensure all updates happen together
    await prisma.$transaction(async (tx) => {
      // If there's a leader, update their role back to engineer
      if (team.leaderId && team.leader) {
        await tx.engineer.update({
          where: { id: team.leaderId },
          data: { 
            role: 'engineer',
            teamId: null,
          },
        })
      }

      // Update all team members to remove team assignment
      if (team.engineers.length > 0) {
        await tx.engineer.updateMany({
          where: { teamId: id },
          data: { teamId: null },
        })
      }

      // Delete the team
      await tx.team.delete({
        where: { id },
      })
    })

    return NextResponse.json({ success: true, message: 'Team deleted successfully' })
  } catch (error) {
    console.error('Error deleting team:', error)
    return NextResponse.json({ error: 'Failed to delete team' }, { status: 500 })
  }
}